sp_widget.client_script:
api.controller = function($scope) {
    var c = this;
    c.submitting = false;
    c.formData = {};

    c.getOptions = function(optStr) {
        if (!optStr) return [];
        return optStr.split(',').map(function(o) {
            return o.trim();
        });
    };

    c.register = function() {
        if (c.submitting) return;
        c.submitting = true;
        c.data.errorMsg = '';
        c.data.success = false;

        c.server.get({
            action: 'register',
            event_id: c.data.event.sys_id,
            formData: c.formData
        }).then(function(r) {
            c.data = r.data;
            c.submitting = false;
        }, function() {
            c.data.errorMsg = 'Network error. Please try again.';
            c.submitting = false;
        });
    };
};

sp_widget.css:
.sp-card {
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-large;
    box-shadow: 0 1px 4px rgba($text-color, 0.07);
    background: $background-primary;
    overflow: hidden;
    margin-bottom: 24px;
}
.sp-card-header {
    padding: 16px 24px;
    background: $background-primary;
    border-bottom: 1px solid $border-tertiary;
}
.sp-card-title {
    font-size: $font-size-large;
    font-weight: 600;
    color: $text-color;
    margin: 0;
}
.sp-card-title .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
}
.sp-card-body {
    padding: 24px;
}
.sp-event-meta p {
    margin-bottom: 8px;
    color: $text-secondary;
    font-size: $font-size-base;
}
.sp-event-meta .glyphicon {
    margin-right: 8px;
    color: $brand-primary;
    font-size: 14px;
}
.sp-input {
    height: $input-height-base;
    border: 1px solid $border-tertiary;
    border-radius: $border-radius-base;
    padding: 0 12px;
    font-size: $font-size-base;
    color: $text-color;
    background: $background-primary;
    transition: border-color 0.15s, box-shadow 0.15s;
    width: 100%;
    &:focus {
        border-color: $brand-primary;
        box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
        outline: none;
    }
}
.sp-textarea {
    border-radius: $border-radius-base;
    border: 1px solid $border-tertiary;
    padding: 12px;
    font-size: $font-size-base;
    resize: vertical;
    min-height: 100px;
    transition: border-color 0.15s;
    &:focus {
        border-color: $brand-primary;
        box-shadow: 0 0 0 3px rgba($brand-primary, 0.15);
        outline: none;
    }
}
.sp-btn-primary {
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    font-weight: 500;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s, box-shadow 0.15s;
    cursor: pointer;
    border: none;
    background: $brand-primary;
    color: $btn-primary-color;
    &:hover:not(:disabled) {
        background: $brand-primary-dark;
        box-shadow: 0 2px 8px rgba($brand-primary, 0.3);
        color: $btn-primary-color;
    }
    &:disabled {
        opacity: 0.55;
        cursor: not-allowed;
    }
}
.sp-btn-secondary {
    background: $background-primary;
    border: 1px solid $border-tertiary;
    color: $text-color;
    height: 44px;
    padding: 0 20px;
    border-radius: $border-radius-base;
    font-size: $font-size-base;
    display: inline-flex;
    align-items: center;
    &:hover {
        background: $background-secondary;
    }
}
.sp-btn-group {
    display: flex;
    gap: 8px;
    align-items: center;
    margin-top: 24px;
    flex-wrap: wrap;
}
@keyframes sp-spin {
    to { transform: rotate(360deg); }
}
.sp-spin {
    animation: sp-spin 0.8s linear infinite;
}

sp_widget.script:
(function() {
    data.event = null;
    data.fields = [];
    data.message = '';
    data.success = false;
    data.errorMsg = '';

    try {
        // Handle registration action
        if (input && input.action === 'register') {
            var regGr = new GlideRecord('x_2097092_linq_registration');
            regGr.initialize();
            regGr.setValue('event', input.event_id);
            regGr.setValue('student', gs.getUserID());
            regGr.setValue('custom_field_data', JSON.stringify(input.formData));
            regGr.setValue('status', 'confirmed');
            regGr.setValue('registration_date', new GlideDateTime().getValue());
            var regId = regGr.insert();

            if (regId) {
                data.success = true;
                data.message = 'Registration successful!';
                data.reg_id = regId + '';
                // Fetch qr_token for the new registration
                var newReg = new GlideRecord('x_2097092_linq_registration');
                if (newReg.get(regId)) {
                    data.qr_token = newReg.getValue('qr_token') + '';
                }
            } else {
                data.errorMsg = 'Registration failed. Please try again.';
            }
            return;
        }

        // Initial load — get event and form fields
        var eventId = $sp.getParameter('event_id');
        if (!eventId) {
            data.errorMsg = 'No event specified.';
            return;
        }

        var eventGr = new GlideRecord('x_2097092_linq_event');
        if (!eventGr.get(eventId)) {
            data.errorMsg = 'Event not found.';
            return;
        }

        data.event = {
            sys_id: eventGr.getUniqueValue(),
            title: eventGr.getValue('title') + '',
            event_date: eventGr.getDisplayValue('event_date') + '',
            venue: eventGr.getValue('venue') + '',
            club_name: eventGr.getDisplayValue('club') + ''
        };

        // Get form template fields
        var ftGr = new GlideRecord('x_2097092_linq_form_template');
        ftGr.addQuery('event', eventId);
        ftGr.orderBy('sort_order');
        ftGr.setLimit(30);
        ftGr.query();

        while (ftGr.next()) {
            var field = {
                sys_id: ftGr.getUniqueValue(),
                field_label: ftGr.getValue('field_label') + '',
                field_type: ftGr.getValue('field_type') + '',
                is_required: ftGr.getValue('is_required') + '' === '1',
                placeholder_text: ftGr.getValue('placeholder_text') + '',
                field_options: ftGr.getValue('field_options') + ''
            };
            data.fields.push(field);
        }
    } catch (e) {
        gs.error('linq-event-registration error: ' + e.message);
        data.errorMsg = 'An error occurred.';
    }
})();
